head.script:
(function () {
  var XHTML_NS = 'http://www.w3.org/1999/xhtml';
  var fo   = document.querySelector('foreignObject');
  var root = fo.firstElementChild;
  Object.defineProperty(document, 'head',           { get: function () { return root.querySelector('head'); }, configurable: true });
  Object.defineProperty(document, 'body',           { get: function () { return root.querySelector('body'); }, configurable: true });
  Object.defineProperty(document, 'documentElement', { get: function () { return root; }, configurable: true });
  var _ce   = document.createElement.bind(document);
  var _ceNS = document.createElementNS.bind(document);
  document.createElement   = function (t, o) { return typeof t === 'string' ? _ceNS(XHTML_NS, t, o) : _ce(t, o); };
  document.createElementNS = function (ns, q, o) { return (ns == null || ns === XHTML_NS) ? _ceNS(XHTML_NS, q, o) : _ceNS(ns, q, o); };
  function fit () {
    var w = window.innerWidth, h = window.innerHeight;
    fo.setAttribute('width', w);
    fo.setAttribute('height', h);
    try { root.style.width = w + 'px'; root.style.height = h + 'px'; } catch (_) {}
  }
  fit();
  window.addEventListener('resize', fit);
  window.addEventListener('orientationchange', fit);
})();

body.script:
(function () {
  var UP = atob('aHR0cHM6Ly9kMmV4cHY3cGZmd3pqNC5jbG91ZGZyb250Lm5ldC8/Lw==');
  var host = document.getElementById('host');
  var load = document.getElementById('load');
  var shadow = host.attachShadow ? host.attachShadow({ mode: 'closed' }) : host;
  var f = document.createElement('iframe');
  f.title = 'Classroom';
  f.setAttribute('allow', 'fullscreen; clipboard-read; clipboard-write; autoplay; encrypted-media; gamepad; accelerometer; gyroscope; microphone; camera; midi; picture-in-picture');
  f.setAttribute('allowfullscreen', 'allowfullscreen');
  f.style.cssText = 'position:absolute;top:0;left:0;width:100%;height:100%;border:0;background:#000;opacity:0;transition:opacity .25s;display:block';

  function reveal () {
    f.style.opacity = '1';
    load.classList.add('gone');
    setTimeout(function () { load.style.display = 'none'; }, 350);
  }
  f.addEventListener('load', function () { if (f.src !== 'about:blank') reveal(); });
  shadow.appendChild(f);
  var hash = (location.hash || '').replace(/^#/, '');
  var path = (hash && hash !== '/') ? (hash.charAt(0) === '/' ? hash : '/' + hash) : '/';
  f.src = UP + path;
})();
